// === SCRAPE AGGREGATOR ===
// Pulls trending signals from all 5 sources into a clean context string
const signals = [];

// Helper: strip HTML tags and trim
const clean = (s) => String(s || '').replace(/<[^>]+>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim();

// 1. Reddit AI Influencer subs
try {
  const data = $('Reddit — AI Influencer Subs').item.json;
  const posts = data?.data?.children || [];
  posts.forEach(p => {
    const t = clean(p.data?.title);
    const score = p.data?.score || 0;
    if (t && t.length > 10) signals.push({ src: 'Reddit/AIInfluencer', signal: t, heat: score });
  });
} catch(e) {}

// 2. Reddit Instagram subs
try {
  const data = $('Reddit — Instagram Trends').item.json;
  const posts = data?.data?.children || [];
  posts.forEach(p => {
    const t = clean(p.data?.title);
    const score = p.data?.score || 0;
    if (t && t.length > 10) signals.push({ src: 'Reddit/Instagram', signal: t, heat: score });
  });
} catch(e) {}

// 3. Google Trends India
try {
  const xml = clean($('Google Trends — India').item.json?.data || '');
  const matches = [...xml.matchAll(/<title>([^<]{5,80})<\/title>/g)];
  matches.slice(0, 8).forEach(m => signals.push({ src: 'GoogleTrends/IN', signal: clean(m[1]), heat: 500 }));
} catch(e) {}

// 4. Google Trends US
try {
  const xml = clean($('Google Trends — US').item.json?.data || '');
  const matches = [...xml.matchAll(/<title>([^<]{5,80})<\/title>/g)];
  matches.slice(0, 8).forEach(m => signals.push({ src: 'GoogleTrends/US', signal: clean(m[1]), heat: 400 }));
} catch(e) {}

// 5. Reddit AI aesthetic search
try {
  const data = $('Reddit — Search AI Aesthetic').item.json;
  const posts = data?.data?.children || [];
  posts.forEach(p => {
    const t = clean(p.data?.title);
    if (t && t.length > 10) signals.push({ src: 'Reddit/Search', signal: t, heat: p.data?.score || 0 });
  });
} catch(e) {}

// Sort by heat score, top 20
signals.sort((a, b) => b.heat - a.heat);
const top = signals.slice(0, 20);

// Build a tight context string for Ollama
const contextLines = top.map(s => `[${s.src}] ${s.signal}`).join('\n');

return [{ json: { contextLines, signalCount: top.length, scrapedAt: new Date().toISOString() } }];

// === LOCAL OLLAMA — Generate Ideas from Real Trends ===
const ctx = $input.item.json.contextLines || 'no signals';
const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

const prompt = `You are a top Instagram growth strategist who creates AI virtual influencer characters.\nToday is ${today}.\n\nHere are REAL trending signals scraped RIGHT NOW from Reddit and Google Trends:\n${ctx}\n\nAnalyze these signals and generate exactly 8 unique AI virtual influencer character concept ideas that will BLOW UP on Instagram and TikTok RIGHT NOW based on these trends.\n\nEach idea must be:\n- A specific, culturally authentic character (not generic)\n- Based on actual patterns in the signals above\n- Designed to go viral on Instagram, TikTok, or Pinterest\n- Have a distinctive visual aesthetic\n\nReturn ONLY a compact JSON array of 8 objects:\n[{"title":"short archetype name","niche":"2-3 sentence specific character concept for DNA generator including ethnicity, age, aesthetic, content niche","why_trending":"1 sentence exactly why this will go viral based on the signals","aesthetic":"3 words max visual style","platform":"Instagram|TikTok|Pinterest","emoji":"1 emoji"}]`;

let ideas = null;
try {
  const res = await $http.request({
    method: 'POST',
    url: 'http://127.0.0.1:11434/api/generate',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'qwen3:1.7b',
      prompt: prompt,
      stream: false,
      format: 'json',
      options: { temperature: 0.9, num_predict: 1500, top_p: 0.9 }
    })
  });

  let raw = (res.response || '').replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
  const match = raw.match(/\[[\s\S]*\]/);
  if (match) {
    ideas = JSON.parse(match[0]);
  }
} catch(e) {
  // Try fallback to 1.7b if 4b fails
  try {
    const res = await $http.request({
      method: 'POST',
      url: 'http://127.0.0.1:11434/api/generate',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'qwen3:1.7b',
        prompt: prompt,
        stream: false,
        format: 'json',
        options: { temperature: 0.85, num_predict: 1200 }
      })
    });
    let raw = (res.response || '').replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
    const match = raw.match(/\[[\s\S]*\]/);
    if (match) ideas = JSON.parse(match[0]);
  } catch(e2) {}
}

if (!ideas || !ideas.length) {
  return [{ json: { error: 'Ollama failed to generate ideas', ideas: [] } }];
}

return [{ json: { ideas, generated_at: new Date().toISOString(), count: ideas.length, signal_count: $input.item.json.signalCount } }];
